<span class="line">  <span class="token keyword">this</span><span class="token punctuation">.</span>lastX <span class="token operator">=</span> currentX<span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">this</span><span class="token punctuation">.</span>lastY <span class="token operator">=</span> currentY<span class="token punctuation">;</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>currentTool <span class="token operator">===</span> <span class="token string">'text'</span> <span class="token operator">||</span> <span class="token keyword">this</span><span class="token punctuation">.</span>currentTool <span class="token operator">===</span> <span class="token string">'mouse'</span><span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> <span class="token keyword">this</span><span class="token punctuation">.</span>isAddingText<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>isDragging<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
