<span class="line">    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>isResizing<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
