<span class="line">      <span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>x <span class="token operator">+</span> <span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>width <span class="token operator">-</span> resizeHandleSize<span class="token punctuation">,</span></span>
