<span class="line">    <span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>y <span class="token operator">+</span> <span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>height <span class="token operator">-</span> resizeHandleSize<span class="token punctuation">,</span></span>
<span class="line">    resizeHandleSize<span class="token punctuation">,</span></span>
<span class="line">    resizeHandleSize</span>
