<span class="line">  <span class="token comment">// 正常情况，按单词换行</span></span>
<span class="line">  <span class="token keyword">let</span> currentLine <span class="token operator">=</span> <span class="token string">''</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">const</span> words <span class="token operator">=</span> text<span class="token punctuation">.</span><span class="token function">split</span><span class="token punctuation">(</span><span class="token string">' '</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> words<span class="token punctuation">.</span>length<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">const</span> word <span class="token operator">=</span> words<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token comment">// 检查单个单词是否已经超过最大宽度</span></span>
<span class="line">    <span class="token keyword">const</span> wordWidth <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>ctx<span class="token punctuation">.</span><span class="token function">measureText</span><span class="token punctuation">(</span>word<span class="token punctuation">)</span><span class="token punctuation">.</span>width<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>wordWidth <span class="token operator">></span> maxWidth<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token comment">// 单个单词超过最大宽度，需要按字符换行</span></span>
<span class="line">      <span class="token keyword">let</span> currentWordLine <span class="token operator">=</span> <span class="token string">''</span><span class="token punctuation">;</span></span>
<span class="line">      <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> j <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> j <span class="token operator">&lt;</span> word<span class="token punctuation">.</span>length<span class="token punctuation">;</span> j<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">const</span> char <span class="token operator">=</span> word<span class="token punctuation">[</span>j<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">const</span> testLine <span class="token operator">=</span> currentWordLine <span class="token operator">+</span> char<span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">const</span> testWidth <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>ctx<span class="token punctuation">.</span><span class="token function">measureText</span><span class="token punctuation">(</span>testLine<span class="token punctuation">)</span><span class="token punctuation">.</span>width<span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token punctuation">(</span>testWidth <span class="token operator">&lt;=</span> maxWidth<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">          currentWordLine <span class="token operator">=</span> testLine<span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">          <span class="token keyword">if</span> <span class="token punctuation">(</span>currentWordLine<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            lines<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>currentWordLine<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">          <span class="token punctuation">}</span></span>
<span class="line">          currentWordLine <span class="token operator">=</span> char<span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">      <span class="token punctuation">}</span></span>
<span class="line">      <span class="token keyword">if</span> <span class="token punctuation">(</span>currentWordLine<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        lines<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>currentWordLine<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">      <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token comment">// 单个单词未超过最大宽度，按单词换行</span></span>
<span class="line">      <span class="token keyword">const</span> testLine <span class="token operator">=</span> currentLine <span class="token operator">+</span> <span class="token punctuation">(</span>currentLine <span class="token operator">?</span> <span class="token string">' '</span> <span class="token operator">:</span> <span class="token string">''</span><span class="token punctuation">)</span> <span class="token operator">+</span> word<span class="token punctuation">;</span></span>
<span class="line">      <span class="token keyword">const</span> testWidth <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>ctx<span class="token punctuation">.</span><span class="token function">measureText</span><span class="token punctuation">(</span>testLine<span class="token punctuation">)</span><span class="token punctuation">.</span>width<span class="token punctuation">;</span></span>
<span class="line">      </span>
<span class="line">      <span class="token keyword">if</span> <span class="token punctuation">(</span>testWidth <span class="token operator">&lt;=</span> maxWidth<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        currentLine <span class="token operator">=</span> testLine<span class="token punctuation">;</span></span>
