<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  <span class="token keyword">this</span><span class="token punctuation">.</span>isAddingText <span class="token operator">=</span> <span class="token boolean">false</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">this</span><span class="token punctuation">.</span>textbox<span class="token punctuation">.</span>content <span class="token operator">=</span> <span class="token string">''</span><span class="token punctuation">;</span></span>
